package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ArtikelDeel;
import be.schaubroeck.lpb.tools.ArtikelDeelType;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.service.ArtikelDeelService;
import be.schaubroeck.lpb.tools.service.util.StandaardLoService;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;

@Slf4j
public class CachedArtikelDeelService extends StandaardLOCachedService<ArtikelDeel> implements CachedService, ArtikelDeelService {

    @Autowired
    private ArtikelDeelService artikelDeelService;

    private static final ThreadLocal<CachedArtikelDeelBuffer> BUFFER = new ThreadLocal<>();

    public CachedArtikelDeelService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ARTIKEL);
    }

    @Override
    @InitializeAdmin
    public ArtikelDeel getByWaarde(Admin admin, ArtikelDeelType deelType, String waarde) {
        TimeLogContext.getInstance().startTimeLogging("CachedArtikelService.getbyFamilieArtikelDelen");
        CachedArtikelDeelBuffer buffer = CachedArtikelDeelService.getBuffer();
        ArtikelDeelKey key = new ArtikelDeelKey(deelType, waarde);
        ArtikelDeel result = buffer.getByKey(key);
        if (result == null) {
            result = artikelDeelService.getByWaarde(admin, deelType, waarde);
            if (result == null) {
                log.warn("ArtikelDeel niet gevonden voor key : {}", key);
            } else {
                buffer.put(key, result);
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public ArtikelDeel getByLangeWaarde(Admin admin, ArtikelDeelType deelType, String langeWaarde) {
        return artikelDeelService.getByLangeWaarde(admin, deelType, langeWaarde);
    }

    @Override
    public ArtikelDeel getByXmlArtikeldeel(Admin admin, ArtikelDeel xmlArtikeldeel) {
        return artikelDeelService.getByXmlArtikeldeel(admin, xmlArtikeldeel);
    }


    @Override
    public void clearCache() {
        CachedArtikelDeelService.getBuffer().clear();
    }

    @Override
    public StandaardLoService<ArtikelDeel> standaardLoService() {
        return (StandaardLoService<ArtikelDeel>) artikelDeelService;
    }

    private static class CachedArtikelDeelBuffer {

        private final Map<ArtikelDeelKey, ArtikelDeel> artikelDeelBuffer = new HashMap<>();
        private final Map<Integer, ArtikelDeel> artikelDeelIdBuffer = new HashMap<>();

        public ArtikelDeel getByKey(ArtikelDeelKey key) {
            return artikelDeelBuffer.get(key);
        }

        public ArtikelDeel getById(Integer id) {
            return artikelDeelIdBuffer.get(id);
        }

        public void put(ArtikelDeelKey key, ArtikelDeel deel) {
            artikelDeelBuffer.put(key, deel);
            artikelDeelIdBuffer.put(deel.getId(), deel);
        }

        public void clear() {
            this.artikelDeelBuffer.clear();
            this.artikelDeelIdBuffer.clear();
        }

    }

    private static CachedArtikelDeelBuffer getBuffer() {
        CachedArtikelDeelBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedArtikelDeelBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    private static class ArtikelDeelKey {

        private Integer typeId;
        private String waarde;

        public ArtikelDeelKey() {
            // default constructor
        }

        public ArtikelDeelKey(ArtikelDeelType deelType, String waarde) {
            this.typeId = deelType.getId();
            this.waarde = waarde;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) {
                return true;
            }
            if (o == null || getClass() != o.getClass()) {
                return false;
            }

            ArtikelDeelKey that = (ArtikelDeelKey) o;

            if (!Objects.equals(typeId, that.typeId)) {
                return false;
            }
            return Objects.equals(waarde, that.waarde);
        }

        @Override
        public int hashCode() {
            int result = typeId != null ? typeId.hashCode() : 0;
            result = 31 * result + (waarde != null ? waarde.hashCode() : 0);
            return result;
        }

        @Override
        public String toString() {
            return "ArtikelDeelKey{" + "typeId=" + typeId + ", waarde='" + waarde + '\'' + '}';
        }
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public void update(Admin admin, ArtikelDeel artikelDeel, boolean forceerUpdate) {
        artikelDeelService.update(admin, artikelDeel, forceerUpdate);
    }

    @Override
    public void checkArtikelDeel(ArtikelDeel artikelDeel) {
        artikelDeelService.checkArtikelDeel(artikelDeel);
    }


    @Override
    public ArtikelDeel create(Admin admin, ArtikelDeel artikel) {
        return artikelDeelService.create(admin, artikel);
    }

    @Override
    public void update(Admin admin, ArtikelDeel artikel) {
        artikelDeelService.update(admin, artikel);
    }

    @Override
    public void delete(Admin admin, ArtikelDeel artikel) {
        artikelDeelService.delete(admin, artikel);
    }

    @Override
    public ArtikelDeel getById(Admin admin, Integer id) {
        return artikelDeelService.getById(admin, id);
    }

    @Override
    public ArtikelDeel getById(Admin admin, Integer id, String fetchFields) {
        return artikelDeelService.getById(admin, id, fetchFields);
    }

    @Override
    public ArtikelDeel getByCriteria(Admin admin, CriteriaBuilder cb) {
        return artikelDeelService.getByCriteria(admin, cb);
    }

    @Override
    public List<ArtikelDeel> findAll(Admin admin) {
        return artikelDeelService.findAll(admin);
    }

    @Override
    public List<ArtikelDeel> findAll(Admin admin, String fetchFields) {
        return artikelDeelService.findAll(admin, fetchFields);
    }

    @Override
    public List<ArtikelDeel> findByCriteria(Admin admin, CriteriaBuilder cb) {
        return artikelDeelService.findByCriteria(admin, cb);
    }

    @Override
    public Integer countByCriteria(Admin admin, CriteriaBuilder cb) {
        return artikelDeelService.countByCriteria(admin, cb);
    }

    @Override
    public Map<Integer, ArtikelDeel> cacheByCriteria(Admin admin, CriteriaBuilder cb) {
        return artikelDeelService.cacheByCriteria(admin, cb);
    }

    @Override
    public List<ArtikelDeel> findByCriteriaTemporalFree(Admin admin, CriteriaBuilder cb) {
        return artikelDeelService.findByCriteriaTemporalFree(admin, cb);
    }

    @Override
    public ArtikelDeel getByCriteriaTemporalFree(Admin admin, CriteriaBuilder cb) {
        return artikelDeelService.getByCriteriaTemporalFree(admin, cb);
    }
}
